{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/Issue2101Test.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRuleBuilder
import org.junit.jupiter.api.Test

/**
 * Tests for issue #2101 - Unexpected indentation level after newline with 0.50.0
 *
 * When a lambda like `{ size -> icon?.getBitmap(size)?.await() }` exceeds the max line length,
 * only the body should be wrapped, not the parameters. The parameters should stay on the same
 * line as the opening brace.
 */
class Issue2101Test {
    private val parameterListWrappingRuleAssertThat =
        assertThatRuleBuilder { ParameterListWrappingRule() }
            .addAdditionalRuleProvider { IndentationRule() }
            .addAdditionalRuleProvider { WrappingRule() }
            .assertThat()

    @Test
    fun `Given a lambda with parameter on same line as opening brace when line exceeds max line length then do not wrap the parameter`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER        $EOL_CHAR
            val foo = { size -> icon?.getBitmap(size)?.await() }
            """.trimIndent()
        parameterListWrappingRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .setMaxLineLength()
            .hasNoLintViolations()
    }

    @Test
    fun `Given a lambda with parameter on same line as opening brace then do not report lint violation`() {
        val code =
            """
            val foo = { size -> icon?.getBitmap(size)?.await() }
            """.trimIndent()
        parameterListWrappingRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a lambda with multiple parameters on same line as opening brace then do not wrap the parameters`() {
        val code =
            """
            val foo = { a, b, c -> doSomething(a, b, c) }
            """.trimIndent()
        parameterListWrappingRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a lambda with parameters already on multiple lines then allow wrapping`() {
        val code =
            """
            val fieldExample =
                LongNameClass { paramA,
                                paramB,
                                paramC ->
                    ClassB(paramA, paramB, paramC)
                }
            """.trimIndent()
        val formattedCode =
            """
            val fieldExample =
                LongNameClass {
                        paramA,
                        paramB,
                        paramC ->
                    ClassB(paramA, paramB, paramC)
                }
            """.trimIndent()
        parameterListWrappingRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .isFormattedAs(formattedCode)
    }
}
"}

